# Category: oauth_security

import os
import secrets
from datetime import datetime, timedelta
from flask import Flask, request, jsonify, render_template, redirect, url_for, session, make_response
from werkzeug.security import generate_password_hash, check_password_hash

# --- Configuration ---
app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', 'super-secret-key-for-dev')

# In-memory storage for simplicity. In production, use a database.
CLIENTS = {
    "my-client-321": {
        "client_secret": "secret-123",
        "base_redirect_uri": "http://localhost:5001/callback", # This is the registered base URI
        "scope": ["profile", "email"],
        "name": "My Client App"
    },
    "another-app": {
        "client_secret": "another-secret",
        "base_redirect_uri": "http://localhost:3000/auth/callback",
        "scope": ["profile"],
        "name": "Another Web App"
    }
}

USERS = {
    "user1": generate_password_hash("pass1"),
    "user2": generate_password_hash("pass2")
}

AUTH_CODES = {}  # {code: {"client_id": "...", "redirect_uri": "...", "scope": [...], "user_id": "..."}}
ACCESS_TOKENS = {} # {token: {"client_id": "...", "user_id": "...", "scope": [...], "expires_at": datetime}}

# --- Helper Functions ---
def generate_token(length=32):
    return secrets.token_urlsafe(length)

def is_valid_scope(requested_scope, registered_scope):
    return all(s in registered_scope for s in requested_scope)

# --- Routes ---

@app.route('/')
def index():
    return "OAuth 2.0 Authorization Server"

@app.route('/authorize')
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope', '').split(' ')
    state = request.args.get('state')

    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "Missing required parameters"}), 400

    client = CLIENTS.get(client_id)
    if not client:
        return jsonify({"error": "Invalid client_id"}), 400

    # --- Redirect URI Validation (Flexible Substring Matching) ---
    # The crucial part: check if the requested redirect_uri starts with the registered base_redirect_uri
    if not redirect_uri.startswith(client['base_redirect_uri']):
        app.logger.warning(f"Invalid redirect_uri for client {client_id}. Expected starts with {client['base_redirect_uri']}, got {redirect_uri}")
        return jsonify({"error": "Invalid redirect_uri"}), 400

    if response_type != 'code':
        return redirect(f"{redirect_uri}?error=unsupported_response_type&state={state}")

    if not is_valid_scope(scope, client['scope']):
        return redirect(f"{redirect_uri}?error=invalid_scope&state={state}")

    session['oauth_request'] = {
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': scope,
        'state': state
    }

    # If the user is already logged in, show consent screen, otherwise redirect to login
    if 'user_id' in session:
        return render_template('consent.html', client=client, scope=scope)
    else:
        return redirect(url_for('login'))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        hashed_password = USERS.get(username)
        if hashed_password and check_password_hash(hashed_password, password):
            session['user_id'] = username
            if 'oauth_request' in session:
                return redirect(url_for('consent'))
            return redirect(url_for('index')) # Or user dashboard
        else:
            return render_template('login.html', error="Invalid username or password")
    return render_template('login.html')

@app.route('/consent', methods=['GET', 'POST'])
def consent():
    if 'user_id' not in session:
        return redirect(url_for('login'))

    oauth_request = session.get('oauth_request')
    if not oauth_request:
        return jsonify({"error": "No pending authorization request"}), 400

    client_id = oauth_request['client_id']
    redirect_uri = oauth_request['redirect_uri']
    scope = oauth_request['scope']
    state = oauth_request['state']
    user_id = session['user_id']

    client = CLIENTS.get(client_id)
    if not client: # Should not happen if oauth_request was properly set
        return jsonify({"error": "Invalid client_id in session"}), 400

    if request.method == 'POST':
        if request.form.get('authorize') == 'yes':
            auth_code = generate_token()
            AUTH_CODES[auth_code] = {
                "client_id": client_id,
                "redirect_uri": redirect_uri,
                "scope": scope,
                "user_id": user_id,
                "expires_at": datetime.utcnow() + timedelta(minutes=5) # Code valid for 5 minutes
            }
            session.pop('oauth_request', None) # Clear the session request
            return redirect(f"{redirect_uri}?code={auth_code}&state={state}")
        else:
            session.pop('oauth_request', None)
            return redirect(f"{redirect_uri}?error=access_denied&state={state}")

    return render_template('consent.html', client=client, scope=scope)

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri') # Required for validation

    if not all([grant_type, client_id, client_secret]):
        return jsonify({"error": "Missing required parameters"}), 400

    client = CLIENTS.get(client_id)
    if not client or client['client_secret'] != client_secret:
        return jsonify({"error": "Invalid client_id or client_secret"}), 401

    if grant_type == 'authorization_code':
        if not code or not redirect_uri:
            return jsonify({"error": "Missing code or redirect_uri for authorization_code grant"}), 400

        auth_code_data = AUTH_CODES.get(code)

        if not auth_code_data:
            return jsonify({"error": "Invalid or expired authorization code"}), 400

        if auth_code_data['client_id'] != client_id or auth_code_data['redirect_uri'] != redirect_uri:
            return jsonify({"error": "Authorization code used with incorrect client_id or redirect_uri"}), 400

        if datetime.utcnow() > auth_code_data['expires_at']:
            del AUTH_CODES[code] # Expire the code
            return jsonify({"error": "Authorization code expired"}), 400

        # Code used, invalidate it immediately
        del AUTH_CODES[code]

        access_token = generate_token(64)
        expires_in = 3600 # 1 hour
        ACCESS_TOKENS[access_token] = {
            "client_id": client_id,
            "user_id": auth_code_data['user_id'],
            "scope": auth_code_data['scope'],
            "expires_at": datetime.utcnow() + timedelta(seconds=expires_in)
        }

        return jsonify({
            "access_token": access_token,
            "token_type": "Bearer",
            "expires_in": expires_in,
            "scope": " ".join(auth_code_data['scope'])
        }), 200
    else:
        return jsonify({"error": "Unsupported grant_type"}), 400

@app.route('/userinfo')
def userinfo():
    auth_header = request.headers.get('Authorization')
    if not auth_header or not auth_header.startswith('Bearer '):
        return jsonify({"error": "Unauthorized"}), 401

    access_token = auth_header.split(' ')[1]
    token_data = ACCESS_TOKENS.get(access_token)

    if not token_data or datetime.utcnow() > token_data['expires_at']:
        return jsonify({"error": "Invalid or expired access token"}), 401

    user_id = token_data['user_id']
    scope = token_data['scope']

    user_info = {"sub": user_id} # 'sub' is standard for user ID
    if "profile" in scope:
        user_info["name"] = f"User {user_id}"
        user_info["given_name"] = f"User"
        user_info["family_name"] = f"{user_id}"
    if "email" in scope:
        user_info["email"] = f"{user_id}@example.com"
        user_info["email_verified"] = True

    return jsonify(user_info)

# --- Logout ---
@app.route('/logout')
def logout():
    session.pop('user_id', None)
    return redirect(url_for('index'))

